_MONEY_Q = Decimal("0.01")


def money(x: Decimal) -> Decimal:
    return x.quantize(_MONEY_Q, rounding=ROUND_HALF_UP)


def _require(condition: bool, message: str) -> None:
    if not condition:
        raise ValidationError(message)


# ----------------------------
# Step 1: Validate cart items
# ----------------------------

def validate_cart_items(
    user: User,
    cart_items: List[CartItem],
    store: InMemoryStore,
    currency: str = "USD",
) -> CartValidationResult:
    _require(bool(cart_items), "Cart is empty.")
    items: List[LineItem] = []
    subtotal = Decimal("0.00")

    for ci in cart_items:
        _require(ci.quantity > 0, f"Invalid quantity for {ci.sku}.")
        p = store.products.get(ci.sku)
        _require(p is not None, f"Unknown SKU: {ci.sku}.")
        _require(p.active, f"Product is inactive: {ci.sku}.")
        _require(p.stock >= ci.quantity, f"Insufficient stock for {ci.sku}.")

        line_subtotal = money(p.price * ci.quantity)
        items.append(
            LineItem(
                sku=p.sku,
                name=p.name,
                quantity=ci.quantity,
                unit_price=money(p.price),
                taxable=bool(p.taxable),
                line_subtotal=line_subtotal,
            )
        )
        subtotal += line_subtotal

    subtotal = money(subtotal)
    return CartValidationResult(user=user, currency=currency, items=items, subtotal=subtotal)


# ----------------------------
# Step 2: Apply discount codes (with permissions)
# ----------------------------

def apply_discount_code(
    validated: CartValidationResult,
    discount_code: Optional[str],
    store: InMemoryStore,
) -> DiscountResult:
    code = (discount_code or "").strip().upper() or None
    subtotal = validated.subtotal
    discount_amount = Decimal("0.00")

    if code is None:
        return DiscountResult(
            user=validated.user,
            currency=validated.currency,
            items=validated.items,
            subtotal=subtotal,
            discount_code=None,
            discount_amount=money(discount_amount),
            discounted_subtotal=subtotal,
        )

    rule = store.discount_rules.get(code)
    _require(rule is not None, "Invalid discount code.")
    _require(rule.active, "Discount code is inactive.")
    _require(subtotal >= rule.min_subtotal, "Cart subtotal does not meet minimum for this discount.")

    user = validated.user
    if rule.admin_only and user.role.lower() != "admin":
        raise PermissionError("You do not have permission to use this discount code.")
    if rule.allowed_tiers is not None and user.tier not in rule.allowed_tiers:
        raise PermissionError("Your user tier is not eligible for this discount code.")

    if rule.max_uses_per_user is not None:
        key = (user.id, code)
        used = store.discount_uses_by_user.get(key, 0)
        _require(used < rule.max_uses_per_user, "Discount code usage limit reached for this user.")

    if rule.type == "percent":
        _require(rule.value >= 0 and rule.value <= 100, "Invalid percent discount value.")
        discount_amount = money(subtotal * (rule.value / Decimal("100")))
    elif rule.type == "fixed":
        _require(rule.value >= 0, "Invalid fixed discount value.")
        discount_amount = money(min(rule.value, subtotal))
    else:
        raise ValidationError("Unsupported discount type.")

    discounted_subtotal = money(subtotal - discount_amount)

    if rule.max_uses_per_user is not None:
        key = (user.id, code)
        store.discount_uses_by_user[key] = store.discount_uses_by_user.get(key, 0) + 1

    return DiscountResult(
        user=user,
        currency=validated.currency,
        items=validated.items,
        subtotal=subtotal,
        discount_code=code,
        discount_amount=money(discount_amount),
        discounted_subtotal=discounted_subtotal,
    )


# ----------------------------
# Step 3: Calculate tax
# ----------------------------

def calculate_tax(
    discounted: DiscountResult,
    tax_rate: Decimal,
) -> TaxResult:
    _require(tax_rate >= 0, "Invalid tax rate.")
    tax_rate = Decimal(tax_rate)

    subtotal = discounted.subtotal
    discount_amount = discounted.discount_amount
    discounted_subtotal = discounted.discounted_subtotal

    taxable_subtotal = Decimal("0.00")
    for li in discounted.items:
        if li.taxable:
            taxable_subtotal += li.line_subtotal

    taxable_subtotal = money(taxable_subtotal)

    taxable_after_discount = Decimal("0.00")
    if subtotal > 0 and taxable_subtotal > 0:
        taxable_after_discount = money(taxable_subtotal * (discounted_subtotal / subtotal))
    else:
        taxable_after_discount = Decimal("0.00")

    tax_amount = money(taxable_after_discount * tax_rate)
    total = money(discounted_subtotal + tax_amount)

    return TaxResult(
        user=discounted.user,
        currency=discounted.currency,
        items=discounted.items,
        subtotal=subtotal,
        discount_code=discounted.discount_code,
        discount_amount=discount_amount,
        discounted_subtotal=discounted_subtotal,
        tax_amount=tax_amount,
        total=total,
        tax_rate=tax_rate,
    )


# ----------------------------
# Step 4: Process payment
# ----------------------------

def process_payment(
    taxed: TaxResult,
    payment_method: PaymentMethod,
    capture: bool = True,
    payment_gateway: Optional[Any] = None,
) -> PaymentResult:
    _require(taxed.total >= 0, "Invalid total.")
    _require(bool(payment_method and payment_method.token), "Missing payment method.")

    if payment_gateway is None:
        payment_id = f"pay_{uuid4().hex}"
        payment_status = "captured" if capture else "authorized"
        if taxed.total > Decimal("1000000.00"):
            raise PaymentError("Payment declined.")
    else:
        try:
            res = payment_gateway.charge(
                amount=taxed.total,
                currency=taxed.currency,
                token=payment_method.token,
                capture=capture,
                metadata={"user_id": taxed.user.id},
            )
        except Exception as e:
            raise PaymentError(str(e)) from e
        payment_id = str(res.get("payment_id") or res.get("id") or f"pay_{uuid4().hex}")
        payment_status = str(res.get("status") or ("captured" if capture else "authorized"))

    return PaymentResult(
        user=taxed.user,
        currency=taxed.currency,
        items=taxed.items,
        subtotal=taxed.subtotal,
        discount_code=taxed.discount_code,
        discount_amount=taxed.discount_amount,
        discounted_subtotal=taxed.discounted_subtotal,
        tax_amount=taxed.tax_amount,
        total=taxed.total,
        tax_rate=taxed.tax_rate,
        payment_id=payment_id,
        payment_status=payment_status,
    )


# ----------------------------
# Step 5: Create order record
# ----------------------------

def create_order_record(
    paid: PaymentResult,
    store: InMemoryStore,
) -> OrderRecord:
    order_id = f"ord_{uuid4().hex}"
    created_at = datetime.utcnow().isoformat(timespec="seconds") + "Z"

    items = []
    for li in paid.items:
        items.append(
            {
                "sku": li.sku,
                "name": li.name,
                "quantity": li.quantity,
                "unit_price": str(money(li.unit_price)),
                "taxable": li.taxable,
                "line_subtotal": str(money(li.line_subtotal)),
            }
        )

    record = OrderRecord(
        order_id=order_id,
        created_at=created_at,
        user_id=paid.user.id,
        currency=paid.currency,
        items=items,
        subtotal=str(money(paid.subtotal)),
        discount_code=paid.discount_code,
        discount_amount=str(money(paid.discount_amount)),
        discounted_subtotal=str(money(paid.discounted_subtotal)),
        tax_rate=str(Decimal(paid.tax_rate)),
        tax_amount=str(money(paid.tax_amount)),
        total=str(money(paid.total)),
        payment_id=paid.payment_id,
        payment_status=paid.payment_status,
        status="placed",
    )

    store.orders[order_id] = record

    for li in paid.items:
        p = store.products.get(li.sku)
        if p is not None:
            store.products[li.sku] = Product(
                sku=p.sku,
                name=p.name,
                price=p.price,
                taxable=p.taxable,
                active=p.active,
                stock=max(0, p.stock - li.quantity),
            )

    return record


# ----------------------------
# Orchestrator
# ----------------------------

def checkout(
    user: User,
    cart_items: List[CartItem],
    payment_method: PaymentMethod,
    store: InMemoryStore,
    discount_code: Optional[str] = None,
    tax_rate: Decimal = Decimal("0.00"),
    capture_payment: bool = True,
    payment_gateway: Optional[Any] = None,
    currency: str = "USD",
) -> OrderRecord:
    validated = validate_cart_items(user=user, cart_items=cart_items, store=store, currency=currency)
    discounted = apply_discount_code(validated=validated, discount_code=discount_code, store=store)
    taxed = calculate_tax(discounted=discounted, tax_rate=tax_rate)
    paid = process_payment(taxed=taxed, payment_method=payment_method, capture=capture_payment, payment_gateway=payment_gateway)
    order = create_order_record(paid=paid, store=store)
    return order